sql:
SELECT title, file_path, file_size, upload_date
FROM documents
WHERE created_by = 0;

SELECT d.title, c.category_name
FROM documents d
JOIN categories c ON d.category_id = c.category_id;

external_knowledge:
- 'blossoming documents' refers to documents that have been published;
- 'gardeners (admins)' refers to users with the role 'admin';
- 'threshold of 500 KB' refers to documents larger than 500 KB in file size;
- 'since the summer of 2022' refers to documents uploaded after June 1, 2022.

sql:
SELECT users.user_name, users.email
FROM users
JOIN documents ON users.user_id = documents.created_by
WHERE documents.file_size = (
    SELECT MAX(file_size) FROM documents
);
